/**
 * WordPress Dependencies
 */
import { __ } from "@wordpress/i18n";
import { assign, isEmpty } from "lodash";
import { link, linkOff } from "@wordpress/icons";
import { addFilter } from "@wordpress/hooks";
import {
	Popover,
	ToolbarGroup,
	ToolbarButton,
	Button,
} from "@wordpress/components";
import { useState } from "@wordpress/element";
import { createHigherOrderComponent } from "@wordpress/compose";
import {
	__experimentalLinkControl as LinkControl,
	BlockControls,
} from "@wordpress/block-editor";
/**
 * Custom Imports
 */
import "./editor.scss";
import "./style.scss";

/**
 * Add new attributes to the block
 */
const EXCLUDED_BLOCKS =
	!isEmpty(ghub_link_any_block_supported_blocks) ||
	ghub_link_any_block_supported_blocks > 0
		? []
		: ghub_link_any_block_unsupported_blocks;

const INCLUDED_BLOCKS = ghub_link_any_block_supported_blocks;
const addAttributes = (settings) => {
	if (isEmpty(settings.attributes) || EXCLUDED_BLOCKS.includes(settings.name)) {
		return settings;
	}
	if (
		!isEmpty(ghub_link_any_block_supported_blocks) ||
		ghub_link_any_block_supported_blocks.length > 0
	) {
		if (INCLUDED_BLOCKS.includes(settings.name)) {
			settings.attributes = assign(
				settings.attributes,
				{
					ghubLink: {
						type: "object",
					},
				},
				{}
			);
		}
	} else {
		settings.attributes = assign(
			settings.attributes,
			{
				ghubLink: {
					type: "object",
				},
			},
			{}
		);
	}

	return settings;
};

const withAdvanceControls = createHigherOrderComponent((BlockEdit) => {
	return (props) => {
		const { attributes, setAttributes, name } = props;
		const [isOpen, setOpen] = useState(false);

		if (EXCLUDED_BLOCKS.includes(name)) {
			return <BlockEdit {...props} />;
		}

		const onClose = () => {
			setOpen(false);
		};
		const onOpen = () => {
			setOpen(true);
		};
		const shouldShowLinkButton =
			!isEmpty(ghub_link_any_block_supported_blocks) ||
			ghub_link_any_block_supported_blocks.length > 0
				? INCLUDED_BLOCKS.includes(name)
				: !EXCLUDED_BLOCKS.includes(name);

		return (
			<>
				<BlockEdit {...props} />
				{shouldShowLinkButton && (
					<BlockControls>
						<ToolbarGroup>
							<ToolbarButton
								onClick={onOpen}
								icon={
									isOpen || !isEmpty(attributes?.ghubLink?.url) ? linkOff : link
								}
								isPressed={!isEmpty(attributes?.ghubLink?.url)}
								label="Link"
							/>
						</ToolbarGroup>
						{isOpen && (
							<Popover placement="bottom" shift onClose={onClose}>
								<LinkControl
									hasTextControl
									hasRichPreviews
									value={attributes.ghubLink}
									withCreateSuggestion={true}
									settings={[
										{
											id: "opensInNewTab",
											title: __("Open in new tab", "ghub-link-any-block"),
										},
										{
											id: "noOpener",
											title: __("No Opener", "ghub-link-any-block"),
										},
										{
											id: "noReferrer",
											title: __("No Referrer", "ghub-link-any-block"),
										},
										{
											id: "noFollow",
											title: __("No Follow", "ghub-link-any-block"),
										},
									]}
									onChange={(updatedValue) => {
										setAttributes({
											ghubLink: updatedValue,
										});
									}}
								/>
								<div className="ghub-link-any-block-unlink-button">
									<Button
										isDestructive
										variant="link"
										onClick={() => {
											setAttributes({ ghubLink: {} });
											onClose();
										}}
									>
										{__("Unlink", "ghub-link-any-block")}
									</Button>
								</div>
							</Popover>
						)}
					</BlockControls>
				)}
			</>
		);
	};
}, "withAdvanceControls");

addFilter(
	"editor.BlockEdit",
	"ghub-link-any-block/with-advance-controls",
	withAdvanceControls
);

addFilter(
	"blocks.registerBlockType",
	"ghub-link-any-block/add-attributes",
	addAttributes
);
